import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

const Widget: React.FC = () => {
  const { recyclingStats, communityLeaderboard } = response.data;
  const { meta } = response;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1C1C1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" sx={{ color: '#4CAF50', mb: 1 }}>
              Recycling Stats
            </Typography>
            <Typography variant="body1">
              Items Recycled: {recyclingStats.itemsRecycled}
            </Typography>
            <Typography variant="body1">
              CO2 Saved: {recyclingStats.co2SavedKg} kg
            </Typography>
            <Typography variant="body1">
              Leaderboard Position: #{recyclingStats.leaderboardPosition}
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: '#4CAF50' }} />

          <Box>
            <Typography variant="h6" sx={{ color: '#FFEB3B', mb: 1 }}>
              Leaderboard Top 5
            </Typography>
            <Stack spacing={1.5}>
              {communityLeaderboard.slice(0, 5).map((user) => (
                <Box key={user.position} sx={{ display: 'flex', justifyContent: 'space-between' }}>
                  <Typography variant="body2">{user.user}</Typography>
                  <Chip label={`${user.itemsRecycled} items`} sx={{ fontSize: '10px', bgcolor: '#4CAF50', color: '#FFFFFF' }} />
                </Box>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: communityLeaderboard.map(user => user.itemsRecycled),
                  color: meta.primaryColor,
                },
              ]}
              xAxis={[
                {
                  data: communityLeaderboard.map(user => user.user),
                  scaleType: 'band',
                  hide: true,
                },
              ]}
              yAxis={[{ hide: true }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
};

export default Widget;
